const express = require('express');
const app = express();
app.use(express.json());

const rewardsBasedOnScore = (score) => {
  if (score >= 1000) { return "Gold Medal"; }
  else if (score >= 500) { return "Silver Medal"; }
  else if (score >= 100) { return "Bronze Medal"; }
  else { return "No Medal"; }
}

app.post('/levelComplete', (req, res) => {
  const { score, time } = req.body;
  if (!score) {
    return res.status(400).send({ error: "Score is required." });
  }

  const reward = rewardsBasedOnScore(score);

  return res.status(200).send({ message: "Level completed successfully.", reward: reward });
});

app.post('/claimReward', (req, res) => {
  const { reward } = req.body;
  if (!reward) {
    return res.status(400).send({ error: "Reward is required." });
  }

  return res.status(200).send({ message: `Reward ${reward} claimed successfully.` });
});

app.listen(3000, () => console.log("Server is up and running on port 3000."));